1	/** A live cell on the infinite Game of Life grid, expressed as `[x, y]`. */
2	export type Cell = [number, number];
3	
4	const NEIGHBOR_OFFSETS: ReadonlyArray<readonly [number, number]> = [
5	  [-1, -1], [-1, 0], [-1, 1],
6	  [ 0, -1],          [ 0, 1],
7	  [ 1, -1], [ 1, 0], [ 1, 1],
8	];
9	
10	const toKey = ([x, y]: Cell): string => `${x},${y}`;
11	const fromKey = (key: string): Cell => {
12	  const [xs, ys] = key.split(",");
13	  return [Number(xs), Number(ys)];
14	};
15	
16	const survives = (isAlive: boolean, neighborCount: number): boolean =>
17	  (isAlive && neighborCount === 2) || neighborCount === 3;
18	
19	/**
20	 * Computes the next generation of live cells from the current generation,
21	 * following Conway's Game of Life rules.
22	 */
23	export function nextGeneration(liveCells: Cell[]): Cell[] {
24	  const liveSet = new Set(liveCells.map(toKey));
25	  const neighborCounts = new Map<string, number>();
26	
27	  for (const [x, y] of liveCells) {
28	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
29	      const key = toKey([x + dx, y + dy]);
30	      neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
31	    }
32	  }
33	
34	  return Array.from(neighborCounts)
35	    .filter(([key, count]) => survives(liveSet.has(key), count))
36	    .map(([key]) => fromKey(key));
37	}
