const willBeAlive = (isAlive: boolean, neighborCount: number): boolean =>
  (isAlive && neighborCount === 2) || neighborCount === 3;

const countNeighbors = (liveCells: Cell[]): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const [x, y] of liveCells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const key = toKey([x + dx, y + dy]);
      counts.set(key, (counts.get(key) ?? 0) + 1);
    }
  }
  return counts;
};

/**
 * Computes the next generation of live cells from the current generation,
 * following Conway's Game of Life rules.
 */
export function nextGeneration(liveCells: Cell[]): Cell[] {
  const liveSet = new Set(liveCells.map(toKey));
  return Array.from(countNeighbors(liveCells))
    .filter(([key, count]) => willBeAlive(liveSet.has(key), count))
    .map(([key]) => fromKey(key));
}
